1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life - Next Generation", () => {
6	  it("should return empty array for empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent live cells with only one neighbor each (underpopulation)", () => {
13	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
14	  });
15	  it("should keep alive a live cell with two live neighbors (survival)", () => {
16	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
17	    expect(result).toContainEqual([1, 0]);
18	  });
19	  it("should keep alive a live cell with three live neighbors (survival)", () => {
20	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
21	    expect(result).toContainEqual([1, 1]);
22	  });
23	  it("should kill a live cell with four live neighbors (overpopulation)", () => {
24	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [0, 1], [1, 1]]);
25	    expect(result).not.toContainEqual([1, 1]);
26	  });
27	  it("should bring a dead cell to life when it has exactly three live neighbors (reproduction)", () => {
28	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
29	    expect(result).toContainEqual([1, 1]);
30	  });
31	  it("should transform a vertical blinker into a horizontal blinker", () => {
32	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
33	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]));
34	    expect(result).toHaveLength(3);
35	  });
36	  it.todo("should keep a block unchanged across generations (still life)");
37	});
