1	type Cell = [number, number];
2	
3	const areNeighbors = (a: Cell, b: Cell): boolean => {
4	  const [ax, ay] = a;
5	  const [bx, by] = b;
6	  if (ax === bx && ay === by) return false;
7	  return Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
8	};
9	
10	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
11	  liveCells.filter((other) => areNeighbors(cell, other)).length;
12	
13	const survives = (liveNeighbors: number): boolean =>
14	  liveNeighbors === 2 || liveNeighbors === 3;
15	
16	const isLive = (cell: Cell, liveCells: Cell[]): boolean =>
17	  liveCells.some(([x, y]) => x === cell[0] && y === cell[1]);
18	
19	const NEIGHBOR_OFFSETS: Cell[] = [
20	  [-1, -1], [-1, 0], [-1, 1],
21	  [ 0, -1],          [ 0, 1],
22	  [ 1, -1], [ 1, 0], [ 1, 1],
23	];
24	
25	const neighborsOf = ([x, y]: Cell): Cell[] =>
26	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
27	
28	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
29	
30	const uniqueCells = (cells: Cell[]): Cell[] => {
31	  const seen = new Map<string, Cell>();
32	  cells.forEach((cell) => seen.set(cellKey(cell), cell));
33	  return [...seen.values()];
34	};
35	
36	const deadNeighborCandidates = (liveCells: Cell[]): Cell[] =>
37	  uniqueCells(liveCells.flatMap(neighborsOf)).filter(
38	    (cell) => !isLive(cell, liveCells),
39	  );
40	
41	export const nextGeneration = (cells: Cell[]): Cell[] => {
42	  const survivors = cells.filter((cell) =>
43	    survives(countLiveNeighbors(cell, cells)),
44	  );
45	  const reborn = deadNeighborCandidates(cells).filter(
46	    (cell) => countLiveNeighbors(cell, cells) === 3,
47	  );
48	  return [...survivors, ...reborn];
49	};
